// Node: "Compute SLA Breach"
// SLA targets by priority (minutes). Mirrors the SLATargets config table;
// swap for an Airtable lookup if targets must be editable without n8n access.
const SLA_MINUTES = {
  Critical: 60,          // 1 hour
  High: 240,             // 4 hours
  Medium: 24 * 60,       // 1 business day (approximated as 24h in v1)
  Low: 48 * 60,          // 2 business days (approximated as 48h in v1)
};
const NEAR_BREACH_RATIO = 0.8;

const out = [];
for (const item of $input.all()) {
  const f = item.json.fields;
  if (!f || !f['Received At']) continue; // no timestamp -> cannot evaluate; skip (no-op, not an error)
  const receivedAt = new Date(f['Received At']).getTime();
  const targetMin = SLA_MINUTES[f['Priority']] || SLA_MINUTES.Medium;
  const ageMin = (Date.now() - receivedAt) / 60000;
  const ratio = ageMin / targetMin;
  if (ratio >= NEAR_BREACH_RATIO) {
    out.push({ json: {
      record_id: item.json.id,
      ticket_id: f['Ticket ID'] || item.json.id,
      priority: f['Priority'] || 'Medium',
      assigned_team: f['Assigned Team'] || 'Customer Success',
      issue_summary: f['Issue Summary'] || '',
      age_minutes: Math.round(ageMin),
      target_minutes: targetMin,
      breached: ratio >= 1,
      near_breach: ratio >= NEAR_BREACH_RATIO && ratio < 1,
    }});
  }
}
// No open tickets past threshold: normal exit, not an error.
return out;

// Node: "Bump Priority One Level" — only for actual breaches, not near-breaches
const ORDER = ['Low', 'Medium', 'High', 'Critical'];
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  let newPriority = j.priority;
  if (j.breached) {
    const idx = ORDER.indexOf(j.priority);
    newPriority = ORDER[Math.min(idx + 1, ORDER.length - 1)] || 'Medium';
  }
  out.push({ json: { ...j, new_priority: newPriority } });
}
return out;

